package com.nattechnologies.trastcms.plugins.saas; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="saas_release") class SaasRelease{@Id@Column(length=36)String id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="product_id")SaasProduct product;@Column(nullable=false,length=80)String version;@Column(nullable=false,length=50)String platform;@Column(nullable=false,length=40)String channel="stable";@Column(name="download_url",nullable=false,length=1000)String downloadUrl;@Column(length=128)String checksum;@Column(name="minimum_plan",length=100)String minimumPlan;@Column(nullable=false)boolean active=true;@Column(name="published_at",nullable=false)Instant publishedAt;@PrePersist void create(){if(id==null)id=UUID.randomUUID().toString();if(publishedAt==null)publishedAt=Instant.now();}}
